const TIMEOUT_MAP = {
  'LEGAL_REVIEW': 120,
  'DRAFT_REPLY': 60,
  'FOLLOW_UP': 240,
  'SCHEDULING': 60,
  'ESCALATE_TO_JR': 30,
};

const now = Date.now();
const timedOut = [];

for (const item of $input.all()) {
  const subject = item.json.subject || '';
  const date = new Date(item.json.date || item.json.internalDate);
  const elapsedMin = (now - date.getTime()) / (1000 * 60);

  // Determine task type from subject
  let taskType = 'UNKNOWN';
  for (const [type, _] of Object.entries(TIMEOUT_MAP)) {
    if (subject.toUpperCase().includes(type)) {
      taskType = type;
      break;
    }
  }

  const timeout = TIMEOUT_MAP[taskType];
  if (timeout && elapsedMin > timeout) {
    timedOut.push({
      json: {
        ...item.json,
        taskType,
        elapsedMin: Math.round(elapsedMin),
        timeoutMin: timeout,
        isTimedOut: true,
      }
    });
  }
}

if (timedOut.length === 0) {
  return [{ json: { isTimedOut: false, message: 'No timeouts detected.' } }];
}

return timedOut;
